var e=(a,o)=>[{name:"Home",path:"/"},{name:"Services",path:"/services"},{name:a,path:o}],i={"trauma-ptsd-therapy":{slug:"trauma-ptsd-therapy",seo:{title:"Trauma & PTSD Therapy Illinois | Faith-Based Telehealth",description:"Trauma-informed, faith-centered therapy for PTSD, complex trauma & childhood emotional neglect. Online across Illinois with Mason L. Kelly, LCSW. 22+ years.",path:"/services/trauma-ptsd-therapy"},eyebrow:"Trauma & PTSD",h1:"Christian Trauma & PTSD Therapy, Online in Illinois",serviceType:"Trauma-focused psychotherapy",intro:"Trauma can leave you feeling unsafe in your own life long after the event has passed. With more than two decades of trauma-focused experience, I offer gentle, paced, faith-integrated care that helps you feel grounded and whole again.",whoFor:["You live with the after-effects of a frightening or overwhelming experience","You experienced childhood abuse or emotional neglect","You feel anxious, on-edge, numb, or easily triggered","You want a therapist who can hold both clinical skill and your faith"],sections:[{heading:"A trauma-informed, client-led approach",body:"We move at the pace your nervous system can tolerate \u2014 never rushing, never forcing. Sessions begin with safety and stabilization before we ever approach difficult memories, and you remain in control of the process throughout."},{heading:"Evidence-based tools, including clinical hypnotherapy",points:["Trauma-focused cognitive behavioral approaches","Clinical hypnotherapy (National Board Certified)","Mindfulness and grounding for telehealth sessions","Care for complex / developmental trauma (C-PTSD)"]},{heading:"How faith can support healing",body:"For clients who want it, Scripture and prayer can become a source of safety and hope in trauma recovery. Faith is always invited at your pace \u2014 never imposed \u2014 and people of all backgrounds are welcome."}],faqs:[{q:"Can trauma therapy really work online?",a:"Yes. Telehealth trauma work is effective and, for many people, feels safer because you are in your own space. We build in grounding techniques designed for online sessions."},{q:"Will I have to talk about everything that happened?",a:"No. You are always in control of what you share and when. Much of trauma healing happens through building safety and new patterns, not through reliving every detail."},{q:"Do you treat childhood trauma and emotional neglect?",a:"Yes. Childhood abuse and emotional neglect are common roots of adult anxiety, depression, addiction, and relationship struggles, and they are a central focus of my work."}],related:[{label:"Abuse & Sexual Abuse Recovery",path:"/services/abuse-sexual-abuse-recovery"},{label:"Depression & Anxiety",path:"/services/depression-anxiety-therapy"},{label:"Addiction & Recovery",path:"/services/addiction-recovery-therapy"}],crumbs:e("Trauma & PTSD Therapy","/services/trauma-ptsd-therapy")},"addiction-recovery-therapy":{slug:"addiction-recovery-therapy",seo:{title:"Addiction & Recovery Therapy Illinois | CADC Telehealth",description:"Faith-centered alcohol & drug addiction therapy with a Certified Alcohol & Drug Counselor (CADC). Online recovery support across Illinois. Mason Kelly, LCSW.",path:"/services/addiction-recovery-therapy"},eyebrow:"Addiction & Recovery",h1:"Addiction & Recovery Therapy: Alcohol & Drug, Faith-Centered",serviceType:"Substance use and addiction counseling",intro:"Addiction is not a moral failure \u2014 it is a painful way of coping with deeper wounds. As a Certified Alcohol & Drug Counselor, I offer compassionate, faith-centered recovery support that treats the whole person, not just the symptom.",whoFor:["You are struggling with alcohol or drug use","You have tried to stop before and want lasting change","You sense that pain or trauma sits underneath the addiction","You want recovery that can include your faith"],sections:[{heading:"Treating the roots, not just the symptoms",body:"Lasting recovery comes from understanding what the substance has been doing for you. Together we address the trauma, anxiety, and shame that so often drive addiction, building healthier ways to meet those needs."},{heading:"Faith-integrated, your way",points:["Certified Alcohol & Drug Counselor (CADC)","Optional integration of biblical principles and 12-step ideas","Relapse-prevention and recovery-supportive living","Care for the family impact of addiction"]},{heading:"A confidential group option",body:"For some clients, the Sex & Relationship Addiction support group offers community and accountability alongside individual work. Group and individual therapy can be combined."}],faqs:[{q:"Do I have to be in recovery already to start?",a:"No. Wherever you are \u2014 considering change, early in recovery, or rebuilding after relapse \u2014 you are welcome. We meet you where you are."},{q:"Is this faith-based or clinical?",a:"Both. I am a licensed clinician and a Certified Alcohol & Drug Counselor, and I integrate faith for clients who want it, alongside evidence-based methods."},{q:"Can you help with the impact on my family?",a:"Yes. Addiction affects the whole family system, and I work with codependency and relationship patterns that often accompany it."}],related:[{label:"Sexual Addiction Therapy",path:"/services/sexual-addiction-therapy"},{label:"Trauma & PTSD Therapy",path:"/services/trauma-ptsd-therapy"},{label:"Codependency Therapy",path:"/services/codependency-therapy"}],crumbs:e("Addiction & Recovery Therapy","/services/addiction-recovery-therapy")},"abuse-sexual-abuse-recovery":{slug:"abuse-sexual-abuse-recovery",seo:{title:"Sexual Abuse Recovery Therapy Illinois | Faith-Based",description:"Trauma-informed, compassionate recovery therapy for survivors of abuse and sexual abuse. Faith-centered, client-led, online in Illinois. Mason Kelly, LCSW.",path:"/services/abuse-sexual-abuse-recovery"},eyebrow:"Abuse & Sexual Abuse Recovery",h1:"Abuse & Sexual Abuse Recovery Therapy, Online in Illinois",serviceType:"Abuse and sexual abuse recovery counseling",intro:"Healing from abuse takes safety, patience, and a therapist who will never rush you. I offer a survivor-paced, deeply respectful space to recover from abuse and sexual abuse \u2014 at your pace, with your consent at every step.",whoFor:["You are a survivor of abuse, sexual abuse, or childhood maltreatment","You struggle with shame, trust, or feeling safe in relationships","You are ready to heal but want to feel in control of the process","You would value a faith-sensitive, compassionate approach"],sections:[{heading:"Safety first, always",body:"Nothing happens here without your readiness and consent. We begin by building safety and stability, and you decide what to explore and when. Healing is possible, and it does not require re-living every detail."},{heading:"Understanding the effects of abuse",points:["Shame, self-blame, and difficulty trusting","Hypervigilance, anxiety, and emotional numbing","Struggles with intimacy and healthy boundaries","The link between past abuse and present coping patterns"]},{heading:"Faith, forgiveness, and self-compassion",body:"For clients who wish, we can explore questions of faith, forgiveness, and self-worth gently and without pressure \u2014 never in a way that minimizes what happened to you or rushes your healing."}],faqs:[{q:"I have never told anyone. Is that okay?",a:"Completely. Many survivors carry their story silently for years. You can share as much or as little as feels right, and we go at your pace."},{q:"Are you a mandated reporter?",a:"Yes, like all licensed clinicians I have certain legal reporting obligations, which I will explain clearly and transparently at the start so there are no surprises."},{q:"Will exploring faith feel pushy?",a:"No. Faith is offered as a resource only if you want it. Your comfort and autonomy always come first."}],related:[{label:"Trauma & PTSD Therapy",path:"/services/trauma-ptsd-therapy"},{label:"Depression & Anxiety",path:"/services/depression-anxiety-therapy"},{label:"Couples & Marriage",path:"/services/couples-marriage-counseling"}],crumbs:e("Abuse & Sexual Abuse Recovery","/services/abuse-sexual-abuse-recovery")},"depression-anxiety-therapy":{slug:"depression-anxiety-therapy",seo:{title:"Depression & Anxiety Therapy Illinois | Faith-Based Online",description:"Faith-centered therapy for depression and anxiety, delivered online across Illinois. Evidence-based, compassionate care with Mason L. Kelly, LCSW. 22+ years.",path:"/services/depression-anxiety-therapy"},eyebrow:"Depression & Anxiety",h1:"Christian Therapy for Depression & Anxiety, Online in Illinois",serviceType:"Depression and anxiety therapy",intro:"When depression or anxiety takes hold, even ordinary days can feel heavy and uncertain. I offer warm, evidence-based therapy \u2014 blended with faith when you want it \u2014 to help you find relief, hope, and steadier ground.",whoFor:["You feel persistently sad, empty, or hopeless","Worry, racing thoughts, or panic interfere with daily life","Stress from work, life transitions, or culture weighs on you","You wonder why faith alone hasn\u2019t resolved how you feel"],sections:[{heading:"Evidence-based relief, blended with faith",body:"Cognitive-behavioral approaches and clinical hypnotherapy help quiet anxious thinking and lift the weight of depression. For clients who want it, faith becomes an anchor of hope rather than a source of guilt."},{heading:"Naming what fuels it",points:["Work-related and life-transition stress","Cultural, political, and identity-related stress","The guilt some Christians feel for struggling at all","Daily coping skills and relapse prevention"]},{heading:"A group option for ongoing support",body:"The biweekly Equanimity group offers community and practical tools for those navigating anxiety and depression, and can complement individual therapy."}],faqs:[{q:"Isn\u2019t faith supposed to be \u201Cenough\u201D for depression?",a:"Struggling with depression or anxiety is not a failure of faith. God works through good clinical care, too. You can honor your faith and get real help at the same time."},{q:"Do you coordinate with prescribers?",a:"Yes. When medication may help, I can coordinate with your physician or psychiatrist as part of a whole-person plan."},{q:"How soon might I feel better?",a:"Everyone is different, but many people begin to feel some relief within the first several sessions as we build skills and understanding together."}],related:[{label:"Trauma & PTSD Therapy",path:"/services/trauma-ptsd-therapy"},{label:"Grief & Loss Counseling",path:"/services/grief-counseling"},{label:"Support Groups",path:"/groups"}],crumbs:e("Depression & Anxiety Therapy","/services/depression-anxiety-therapy")},"sexual-addiction-therapy":{slug:"sexual-addiction-therapy",seo:{title:"Sexual Addiction Therapy Illinois | CSOTS Telehealth",description:"Confidential, compassionate therapy for sexual addiction and compulsive behavior. Faith-centered, online in Illinois. Mason L. Kelly, LCSW, CSOTS, CADC.",path:"/services/sexual-addiction-therapy"},eyebrow:"Sexual Addiction",h1:"Sexual Addiction Therapy: Confidential, Faith-Centered Care",serviceType:"Sexual addiction and compulsive behavior counseling",intro:"Compulsive sexual behavior thrives in secrecy and shame. In a confidential, non-condemning space, I help adults understand and recover from sexual addiction \u2014 addressing the pain underneath, not just the behavior.",whoFor:["You feel out of control with pornography or sexual behavior","Secrecy and shame are damaging your relationships or self-worth","You want discreet, specialized, non-judgmental help","You would value faith-integrated accountability and recovery"],sections:[{heading:"A clinical, not condemning, understanding",body:"Compulsive sexual behavior is often a way of soothing trauma, loneliness, or stress. We replace shame with understanding and build genuine, sustainable change \u2014 with specialized clinical expertise."},{heading:"Specialized expertise and a recovery path",points:["Certified Sex Offender Treatment Specialist (CSOTS) training","Pornography, infidelity, and compulsive patterns","Treating underlying trauma and shame","Faith-integrated accountability, at your choice"]},{heading:"Support for partners and a group option",body:"Compulsive behavior affects partners deeply. I can support couples work where appropriate, and the monthly Sex & Relationship Addiction group offers confidential community."}],faqs:[{q:"Is this completely confidential?",a:"Yes. Sessions are private and held over secure telehealth, within the standard limits of clinical confidentiality, which I explain at the outset."},{q:"Will I be judged or shamed?",a:"Never. My approach is clinical and compassionate. Shame keeps the cycle going; understanding and support are what create lasting change."},{q:"Can my partner be involved?",a:"Where it is helpful and you both wish it, couples sessions can support rebuilding trust alongside your individual recovery work."}],related:[{label:"Addiction & Recovery Therapy",path:"/services/addiction-recovery-therapy"},{label:"Couples & Marriage",path:"/services/couples-marriage-counseling"},{label:"Support Groups",path:"/groups"}],crumbs:e("Sexual Addiction Therapy","/services/sexual-addiction-therapy")},"couples-marriage-counseling":{slug:"couples-marriage-counseling",seo:{title:"Christian Marriage Counseling Illinois | Online Couples",description:"Faith-centered couples and marriage counseling online in Illinois. Rebuild trust after infidelity, improve communication & reconnect. Mason Kelly, LCSW.",path:"/services/couples-marriage-counseling"},eyebrow:"Couples & Marriage",h1:"Couples & Marriage Counseling, Online Across Illinois",serviceType:"Couples and marriage counseling",price:160,intro:"Every relationship hits seasons of distance, conflict, or broken trust. I help couples across Illinois reconnect, communicate, and rebuild \u2014 with care that can be grounded in your shared faith.",whoFor:["You and your partner feel stuck in conflict or distance","Trust has been broken and you want to heal it","You want to communicate without the same painful cycles","You share a faith you\u2019d like woven into your work"],sections:[{heading:"Common issues we work through",points:["Communication breakdowns and recurring conflict","Rebuilding trust after infidelity","Intimacy, connection, and life transitions","Codependency and unhealthy relationship patterns"]},{heading:"Rebuilding trust after infidelity",body:"Recovering from betrayal is hard but possible. We move step by step \u2014 creating safety, understanding what happened, and rebuilding honesty and connection \u2014 at a pace you both can manage."},{heading:"Faith as a shared foundation",body:"When both partners want it, shared faith and values can become a powerful foundation for healing. Sessions are $160 and held securely online."}],faqs:[{q:"What if only one of us wants counseling?",a:"That\u2019s common. We can start with whoever is ready, and meaningful change in one partner often opens the door for the other."},{q:"Do you only see Christian couples?",a:"No. Couples of all backgrounds are welcome. Faith is integrated only to the degree you both want."},{q:"How much are couples sessions?",a:"Couples sessions are $160, with a sliding scale available. Many insurance plans provide coverage \u2014 see the Fees & Insurance page."}],related:[{label:"Sexual Addiction Therapy",path:"/services/sexual-addiction-therapy"},{label:"Codependency Therapy",path:"/services/codependency-therapy"},{label:"Abuse & Sexual Abuse Recovery",path:"/services/abuse-sexual-abuse-recovery"}],crumbs:e("Couples & Marriage Counseling","/services/couples-marriage-counseling")},"grief-counseling":{slug:"grief-counseling",seo:{title:"Christian Grief Counseling Illinois | Online Telehealth",description:"Compassionate, faith-centered grief and loss counseling online across Illinois. Support through bereavement, complicated grief & life transitions. Mason Kelly LCSW.",path:"/services/grief-counseling"},eyebrow:"Grief & Loss",h1:"Grief & Loss Counseling, Faith-Centered and Online in Illinois",serviceType:"Grief and loss counseling",intro:"Grief is love with nowhere to go. Whether you are mourning a death or another deep loss, I offer gentle, faith-centered companionship through sorrow \u2014 without ever rushing you toward \u201Cmoving on.\u201D",whoFor:["You are grieving the death of someone you love","You are facing loss through divorce, illness, or major change","Your grief feels complicated, stuck, or overwhelming","You long for hope that honors both faith and sorrow"],sections:[{heading:"Grief beyond death",body:"Loss takes many forms \u2014 divorce, estrangement, identity loss, the life you imagined. All of it deserves to be grieved, and there is no \u201Cright\u201D timeline for any of it."},{heading:"A faith-centered view of hope and mourning",points:["Naming and honoring your loss without rushing it","Support for bereavement, anticipatory, and complicated grief","When grief overlaps with depression or trauma","Rituals and meaning-making that bring comfort"]}],faqs:[{q:"It\u2019s been a long time. Is it too late for grief counseling?",a:"It is never too late. Grief doesn\u2019t follow a schedule, and support can help whether your loss was last month or many years ago."},{q:"Will you tell me my loved one is \u201Cin a better place\u201D?",a:"My job is to walk with you in your grief, not to rush you past it. Faith and hope are offered gently, at your pace and in your own words."}],related:[{label:"Depression & Anxiety",path:"/services/depression-anxiety-therapy"},{label:"Trauma & PTSD Therapy",path:"/services/trauma-ptsd-therapy"},{label:"Detransition Support",path:"/detransition-support"}],crumbs:e("Grief & Loss Counseling","/services/grief-counseling")},"eating-disorder-therapy":{slug:"eating-disorder-therapy",seo:{title:"Eating Disorder Therapy Illinois | Faith-Based Online",description:"Compassionate, faith-centered therapy for eating disorders and body image, online in Illinois. Trauma-informed, client-led care with Mason L. Kelly, LCSW.",path:"/services/eating-disorder-therapy"},eyebrow:"Eating Disorders",h1:"Eating Disorder Therapy, Compassionate & Faith-Centered",serviceType:"Eating disorder and body-image therapy",intro:"Disordered eating is rarely about food \u2014 it is often about control, pain, and a longing to feel safe. I offer compassionate, non-judgmental, faith-centered therapy for eating and body-image struggles.",whoFor:["Your relationship with food or your body causes distress","You use food to cope with difficult emotions","Shame and control feel tangled up with eating","You want care that respects your faith and your body"],sections:[{heading:"Understanding the roots",body:"Eating struggles often grow from trauma, anxiety, control, and shame. We address those roots with compassion, building a kinder, steadier relationship with food and self."},{heading:"A client-led, weight-inclusive approach",points:["Non-judgmental, collaborative, and paced by you","Body image, identity, and self-worth beyond appearance","Coordination with medical providers and dietitians","Tools for recovery and relapse prevention"]}],faqs:[{q:"Do I need a medical team too?",a:"For many eating concerns, coordinated care with a physician and dietitian is important. I am glad to work alongside your medical providers."},{q:"Will you focus on my weight?",a:"No. My approach is weight-inclusive and focused on your relationship with food, your body, and the emotions underneath \u2014 not a number on a scale."}],related:[{label:"Trauma & PTSD Therapy",path:"/services/trauma-ptsd-therapy"},{label:"Depression & Anxiety",path:"/services/depression-anxiety-therapy"},{label:"Detransition Support",path:"/detransition-support"}],crumbs:e("Eating Disorder Therapy","/services/eating-disorder-therapy")},"codependency-therapy":{slug:"codependency-therapy",seo:{title:"Codependency Therapy Illinois | Faith-Based Online",description:"Heal codependency and childhood emotional neglect with faith-centered, client-led therapy online in Illinois. Build boundaries & self-worth. Mason Kelly, LCSW.",path:"/services/codependency-therapy"},eyebrow:"Codependency",h1:"Codependency & Childhood Emotional Neglect Recovery Therapy",serviceType:"Codependency and relationship-pattern therapy",intro:"If you lose yourself in caring for everyone else, struggle to set boundaries, or tie your worth to being needed, you are not alone. I help adults heal codependency and the childhood roots beneath it.",whoFor:["You over-give and struggle to say no","Your self-worth depends on others\u2019 approval or needs","You grew up with emotional neglect or a chaotic home","You love someone whose addiction has shaped your life"],sections:[{heading:"Recognizing codependency",body:"Codependency often grows from childhood emotional neglect, where caretaking became a way to feel safe or valued. Naming the pattern is the first step toward freedom from it."},{heading:"Building boundaries and self-worth",points:["Childhood emotional neglect (CEN) and inner-child roots","Boundaries, self-worth, and breaking over-responsibility","Codependency alongside a loved one\u2019s addiction","Reparenting and self-compassion skills"]},{heading:"Faith and identity",body:"For clients who want it, we ground worth in something deeper than caretaking \u2014 in being loved and valued as you are, not for what you do for others."}],faqs:[{q:"Is codependency a real diagnosis?",a:"Codependency is a well-recognized relational pattern rather than a formal diagnosis. It is very treatable, and therapy can help you build healthier, freer relationships."},{q:"I\u2019m here because of someone else\u2019s addiction. Can you help?",a:"Yes. Loving someone with an addiction often shapes codependent patterns. We can focus on your needs, boundaries, and healing."}],related:[{label:"Addiction & Recovery Therapy",path:"/services/addiction-recovery-therapy"},{label:"Couples & Marriage",path:"/services/couples-marriage-counseling"},{label:"Trauma & PTSD Therapy",path:"/services/trauma-ptsd-therapy"}],crumbs:e("Codependency Therapy","/services/codependency-therapy")}},n=Object.keys(i);export{i as a};
